const input = $input.first().json;

function isRecord(value) {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function parseUrlEncodedBody(body) {
  const params = new URLSearchParams(body);
  return Object.fromEntries(params.entries());
}

function normalizeSlackPayload(source) {
  const nestedBody = source.body;

  if (isRecord(nestedBody)) {
    return nestedBody;
  }

  if (typeof nestedBody === 'string' && nestedBody.trim()) {
    const trimmed = nestedBody.trim();

    if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
      try {
        const parsed = JSON.parse(trimmed);
        if (isRecord(parsed)) {
          return parsed;
        }
      } catch {
        // Fall through to urlencoded parsing.
      }
    }

    return parseUrlEncodedBody(trimmed);
  }

  return source;
}

const body = normalizeSlackPayload(input);

// ── URL verification challenge (Slack Event API setup) ────────────────────
if (body.type === 'url_verification') {
  return [{ json: { type: 'challenge', challenge: body.challenge } }];
}

// ── Slash command (application/x-www-form-urlencoded parsed by n8n) ──────
const command = (body.command || '').toLowerCase().trim();
const rawText = (body.text || '').trim();
const channelId = body.channel_id || '';
const userId = body.user_id || '';
const userName = body.user_name || '';
const responseUrl = body.response_url || '';

// Commands that create a new pipeline run
const CREATE_MAP = {
  '/plan': 'planner',
  '/adp-plan': 'planner',
  '/sprint': 'sprint-controller',
  '/adp-sprint': 'sprint-controller',
  '/implement': 'implementer',
  '/adp-implement': 'implementer',
  '/verify': 'verifier',
  '/adp-verify': 'verifier',
};

// Commands that operate on an existing pipeline run
// Text format: /approve <pipeline-id>
// /handoff <pipeline-id> [artifact-path]
const ACTION_MAP = {
  '/approve': 'approve',
  '/adp-approve': 'approve',
  '/takeover': 'takeover',
  '/adp-takeover': 'takeover',
  '/handoff': 'handoff',
  '/adp-handoff': 'handoff',
  '/status': 'status',
  '/adp-status': 'status',
};

if (CREATE_MAP[command]) {
  return [{
    json: {
      type: 'create_pipeline',
      entry_point: CREATE_MAP[command],
      description: rawText,
      channel_id: channelId,
      user_id: userId,
      user_name: userName,
      response_url: responseUrl,
    }
  }];
}

if (ACTION_MAP[command]) {
  const parts = rawText.split(' ').filter(Boolean);
  const pipeline_id = parts[0] || '';
  const artifact_path = parts[1] || '';
  return [{
    json: {
      type: 'pipeline_action',
      action: ACTION_MAP[command],
      pipeline_id,
      artifact_path,
      channel_id: channelId,
      user_id: userId,
      user_name: userName,
      response_url: responseUrl,
    }
  }];
}

// Unknown command
return [{
  json: {
    type: 'unknown',
    command,
    response_url: responseUrl,
  }
}];

const pipeline = $input.first().json;
const stepLabel = (pipeline.entry_point || 'planner').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
return [{
  json: {
    response_body: JSON.stringify({
      response_type: 'in_channel',
      text: `\u23F3 Pipeline \`${pipeline.pipeline_id}\` started — running *${stepLabel}*...\nI'll post an update in this thread when it's ready for review.`
    })
  }
}];

const data = $input.first().json;
const { action, pipeline_id, artifact_path, user_name, user_id } = data;
const actor = user_name || user_id || 'unknown';

if (!pipeline_id) {
  return [{
    json: {
      skip_http: true,
      response_body: JSON.stringify({
        response_type: 'ephemeral',
        text: `\u274C Please provide a pipeline ID: \`/${action} <pipeline-id>\``
      })
    }
  }];
}

const base = 'https://__EXECUTION_API_BASE_URL__';
let method = 'POST';
let url;
let body;

if (action === 'approve') {
  url = `${base}/pipeline/${pipeline_id}/approve`;
  body = JSON.stringify({ actor });
} else if (action === 'takeover') {
  url = `${base}/pipeline/${pipeline_id}/takeover`;
  body = JSON.stringify({ actor });
} else if (action === 'handoff') {
  url = `${base}/pipeline/${pipeline_id}/handoff`;
  body = JSON.stringify({ actor, artifact_path: artifact_path || undefined });
} else if (action === 'status') {
  method = 'GET';
  url = `${base}/pipeline/${pipeline_id}`;
  body = null;
}

return [{ json: { ...data, actor, skip_http: false, http_method: method, http_url: url, http_body: body } }];

const result = $input.first().json;
const action = $('Build Action Request').first().json.action;
const pipeline_id = $('Build Action Request').first().json.pipeline_id;

let text;
if (action === 'approve') {
  text = `\u2705 Approved — pipeline \`${pipeline_id}\` is advancing.`;
} else if (action === 'takeover') {
  text = `\u270B Takeover confirmed — you now own the current step on \`${pipeline_id}\`.\nUse \`/handoff ${pipeline_id}\` when you're done.`;
} else if (action === 'handoff') {
  text = `\u2705 Handoff complete — pipeline \`${pipeline_id}\` is resuming.`;
} else if (action === 'status') {
  const run = result;
  const step = (run.current_step || '').replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
  text = `*Pipeline* \`${pipeline_id}\`\n*Status:* ${run.status}\n*Step:* ${step}\n*Steps:* ${(run.steps || []).map(s => `${s.role}: ${s.status}`).join(' → ')}`;
}

return [{ json: { response_body: JSON.stringify({ response_type: 'in_channel', text }) } }];
